exercise.solution:
class Vehicle:
    def __init__(self, make, model):
        self.make = make
        self.model = model

    def describe(self):
        print(f"{self.make} {self.model}")


class Car(Vehicle):
    def __init__(self, make, model, doors):
        super().__init__(make, model)
        self.doors = doors

    def describe(self):
        super().describe()
        print(f"  Doors: {self.doors}")


class Motorcycle(Vehicle):
    def __init__(self, make, model, has_sidecar):
        super().__init__(make, model)
        self.has_sidecar = has_sidecar

    def describe(self):
        super().describe()
        sidecar_info = "has a sidecar" if self.has_sidecar else "no sidecar"
        print(f"  Sidecar: {sidecar_info}")


my_car = Car("Toyota", "Camry", 4)
my_bike = Motorcycle("Harley-Davidson", "Sportster", False)

my_car.describe()
my_bike.describe()
